@startuml
title Sistema_de_Cobranças

class Cliente {
  + id: Int
  + nome: String
  + cobranças: List<Cobrança>
  + fazerPagamento()
}

class Cobrança {
  + id: Int
  + cliente: Client
  + quitado: Boolean
  + gerarBoleto()
  + consultaBoleto(): Boolean
}

class Boleto {
  + id: Int
  + validade: Date
  + valor: Float
  +
}

interface GerarBoleto {
}

interface PagarBoleto {
  + fazerPagamento()
}

Cliente --|> GerarBoleto
Cliente --|> PagarBoleto

Cliente "1" -- "0..*" Cobrança
Cobrança "1" -- "1" Boleto

@enduml
